var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"3종 침식체 격파 확인.","JPN":"第3種侵食体の撃破確認。","ENG":"The Category 3 C.O. is gone.","TWN":"3類侵蝕體確認已遭擊斃。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이제 주위에 비슷한 기운은 느껴지지 않네. 소탕 완료야.","JPN":"もう周りから似たような気配は感じられないわ。掃討完了よ。","ENG":"I do not feel any similar aura nearby. We cleared the area.","TWN":"現在周圍已經感覺不到類似的氣息，掃蕩完成。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"3종을 이렇게 간단하게 잡았단 말이야?","JPN":"第3種をこんなにも簡単にやっつけたのか？","ENG":"We defeated a Category 3 that easily?","TWN":"竟然這麼輕鬆就擊斃3類？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당신들, 내가 생각했던 것보다 훨씬 강하구나.","JPN":"汝らの強さは妾の想像以上だな。","ENG":"You two are much stronger than I thought.","TWN":"你們，比我想像中的還要強呢。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유의 검술이 뛰어난 것도 있지만, 서로의 합이 잘 맞은 게 컸습니다.","JPN":"千冬の剣術が優れていることもありますが、お互いの息がよく合っていたからでしょう。","ENG":"Chifuyu is excellent with her sword, but it was also because we worked well together as a team.","TWN":"千冬的劍術固然出色，但更多的是我們之間的默契。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"게다가 라우라 공과 플루토 공의 보조가 힘이 됐습니다.","JPN":"それに、ラウラ殿とプルート殿の補助に助けられました。","ENG":"You and Sir Pluto were of great help.","TWN":"而且蘿拉和普魯托的支援也很給力。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님까지 세 분의 보조가 있으니 이리 손쉽게 격파할 수 있었던 거지요.","JPN":"当主を含め三人の補助があったからこそ、こうして容易に撃破できたのでしょう。","ENG":"Your assistance, combined with Lady Nanahara's assistance, was what made it so easy.","TWN":"多虧有堂主和你們的支援，我才能這麼輕鬆就能擊敗它。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"고생했어. 치후유. 다친 덴 없니?","JPN":"お疲れ様、千冬。怪我はない？","ENG":"Good job, Chifuyu. Are you okay?","TWN":"千冬辛苦了，你沒受傷吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"다친 데는 없으니 이제 그만 놔주셔도 됩니다.","JPN":"怪我はありませんので、それくらいでお放しください。","ENG":"I am not hurt. You can let go of me now.","TWN":"我沒事，堂主可以鬆開了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"뜨거우실 텐데요.","JPN":"熱いはずですから。","ENG":"I know it must be hot.","TWN":"這樣堂主會熱。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후후. 동생의 뜨거운 몸까지 받아줄 수 있어야 언니랍니다.","JPN":"ふふ。妹の熱い体も受け止められてこそ姉さんなのです。","ENG":"Hehe. I should be able to embrace your warm body as the older sister.","TWN":"呵呵，當姊姊的就是要能接受妹妹的體溫。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"하지만 당주님, 계속 안고 계시면 저온 화상을 입게 됩니다.","JPN":"ですが当主、ずっと抱いていると低温火傷を負います。","ENG":"But, my lady, you will get burnt if you keep hugging me.","TWN":"但是堂主再繼續抱下去的話，我擔心堂主會低溫燙傷。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"정말 만져보니 몸이 뜨겁네. 이게 아픈 게 아니란 말이야?","JPN":"触ってみると本当に体が熱いのだな。病気ではないのだろう？","ENG":"Your body really does run hot. And you're sure you're not sick?","TWN":"摸起來真的很熱，你不難受嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"확실히, 이런 다 벗은 거나 다름없는 옷을 입고 다니는 이유가 있었어.","JPN":"確かに、これなら極端に布の少ない服を着ている理由も納得がいく。","ENG":"I can see why you'd wear something so revealing.","TWN":"原來，這就是你穿這種幾乎衣不蔽體的衣服的原因嗎。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그저 통기성이 좋은 옷일 뿐입니다.","JPN":"通気性に優れた服だと思いますが？","ENG":"It is simply more breathable.","TWN":"這只是一件透氣性的衣服而已。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"……. 그럼 옷을 만들 때 통기성이 좋은 디자인도 참고할게.","JPN":"……それでは、服を仕立てる時に通気性の良いデザインも参考にしよう。","ENG":"...I'll take a look at more breathable designs when I make your outfit, then.","TWN":"……那我在設計衣服時也要考慮到透氣的問題。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"3종 침식체한테서 재료도 얻었고, 당분간 지하실에 올 일이 없겠는데?","JPN":"第3種侵食体から材料も入手したことだし、しばらく地下室に来る必要はなさそうだな。","ENG":"Since I got some material from the Category 3 C.O., that should save me from coming down to the basement for a while.","TWN":"既然已經從3類侵蝕體身上取得材料，我想應該暫時不會再來地下室。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"고마워. 솔직히 외부인을 여기 데리고 온다는 게 쉬운 결정은 아니었거든.","JPN":"世話になった。正直、部外者をここに連れてくるという決断はそう簡単なものではないのだ。","ENG":"Thank you. It wasn't an easy decision to bring outsiders in here.","TWN":"謝謝你們。說實話，要帶外人來這裡並不是容易的決定。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"덕분에 일이 수월해졌어.","JPN":"おかげで楽に仕事ができた。","ENG":"But you made things a lot easier.","TWN":"多虧有你們，事情才能這麼順利。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후후. 어찌 보면 라우라 님은 저희에겐 은인.","JPN":"ふふ。ある意味でラウラ様は私たちの恩人。","ENG":"Hehe. I would say we owe you, in a way.","TWN":"呵呵。某種程度上，蘿拉也算是我們的恩人。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어찌 은인의 곤란함을 외면할 수 있겠습니까?","JPN":"困っている恩人を、見て見ぬふりなどできましょうか。","ENG":"So how could we ignore someone we owe?","TWN":"恩人有難，怎麼能不出手相助呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"더군다나 저희 의상을 만들기 위해 싸우셔야 한다면.","JPN":"それに、私たちの衣装を作るための戦いとあればなおのこと。","ENG":"And if you were to fight to create our costume,","TWN":"更何況是因為要製作我們的衣服，"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"저희 역시 함께 싸울 뿐입니다.","JPN":"共に戦わない理由などありません。","ENG":"we would also join the fight. It is as simple as that.","TWN":"我們當然要一起戰鬥。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"성격은 둘이 다른 거 같았는데, 이런 데서 묘하게 닮았구나? 너희.","JPN":"二人の性格は違うと思っていたが、こんなところでは妙に似ているのだな。汝ら。","ENG":"I thought you two had very different personalities. But it's weirdly similar for matters like this.","TWN":"你們二個性格雖然不同，但在這種時候到是很像呢？真不愧是姊妹。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하긴, 뭐라도 닮은 구석이 있어야 자매겠지.","JPN":"まあ、似たところがあるからこそ姉妹なのだろう。","ENG":"I guess you can't be sisters without some similarities, right?","TWN":"也是，總要某些地方像才算是姊妹嘛。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"돌아가자고. 재료도 다 모았겠다, 시안도 있겠다.","JPN":"帰ろう。材料もすべて集めたし、デザインの案もある。","ENG":"Let's head back. We have all the materials and the design.","TWN":"回去吧，現在材料和設計都有了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"축제에 가려면 빨리 진행해야지.","JPN":"お祭りに行くなら早く進めないと。","ENG":"We have to hurry if you want to make it to the festival.","TWN":"要參加活動的話，必須趕快動工才行。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그럼 귀환하시겠습니까?","JPN":"それでは、帰還しますか？","ENG":"Shall we return, then?","TWN":"那就回去吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"라우라님도 고생 많으셨어요. 다친 곳이 있다면 제가 치유해드리겠습니다.","JPN":"ラウラ様もお疲れ様でした。お怪我がありましたら、私が治療いたします。","ENG":"Thank you for your hard work, Miss Laura. I can treat you if you have any injuries.","TWN":"蘿拉也辛苦了，如果哪裡有受傷的話，我可以幫你治療。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그쪽의 동생이 활약해준 덕에 상처 하나 안 났어. 얼른 올라가자.","JPN":"そちらの妹が活躍してくれたおかげで、傷一つない。早く上がろう。","ENG":"Not even a scratch, thanks to your sister flying around and cutting everything. Let's go up.","TWN":"多虧你妹妹的幫忙，完全沒受傷。我們快上去吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"어으, 무거워. 다 갖고 오려면 지하실을 몇 번 왔다 갔다 해야겠는데?","JPN":"ううっ、重い。全部持って来るには何回か地下室を往復する必要がありそうだな。","ENG":"Ooof, that's heavy. We might have to make multiple trips to bring everything back up.","TWN":"噢噢，好重喔。看來還要再來回地下室幾趟才能拿完。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"양이 너무 많은가요?","JPN":"量が多すぎるのですか？","ENG":"Is it too much?","TWN":"量太多了嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라는 지금 기분이 좋은 거야, 꼬마 무녀님.","JPN":"ラウラは今上機嫌なのよ、ちびっ子巫女さん。","ENG":"Laura is actually in a good mood, little priestess.","TWN":"蘿拉現在心情好得很喔，小女巫。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"재료가 많을수록 양질의 의상이 탄생할 가능성이 높으니까.","JPN":"材料が多ければ多いほど、良質の衣装ができる可能性が高いからね。","ENG":"The more materials, the higher the chances of creating a good quality costume.","TWN":"因為材料越多，做出現優質服裝的可能性就越高。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"게다가 3종 침식체가 나타났었다며?","JPN":"それに、第3種侵食体が現れたんだって？","ENG":"I heard there was even a Category 3 C.O.","TWN":"而且我聽說還有出現3類侵蝕體？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 더 좋은 옷이 나오겠는걸?","JPN":"じゃあ、もっといい服ができるかもしれないわよ？","ENG":"That should make for an even better costume.","TWN":"那一定會是很棒的衣服吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"설명 부탁한 적 없거든?","JPN":"説明は頼んでないんだが。","ENG":"Nobody asked you to explain.","TWN":"誰讓你說這麼多的？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"좋아. 이 정도면 내가 만든 의상 중 손에 꼽을 정도로 훌륭하게 나올 수 있겠어.","JPN":"よし。これなら妾が作った衣装の中でもとびっきりの衣装が作れそうだ。","ENG":"Good. This should allow me to create something I could put in my top five costumes!","TWN":"很好，有這些材料，這次的衣服應該會是我做過的衣服之中數一數二的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"잠깐만 기다려. 내가 동생한테 어울리는 최고의 의상을 만들어 줄 테니까.","JPN":"少し待っていろ。妾が妹にぴったりの最高の衣装を作ってあげよう。","ENG":"Hold on a second. I'm going to make the best costume that fits your sister.","TWN":"等我一下，我會為妹妹做出最適合的衣服。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이렇게 마음껏 재료를 넣은 게 얼마 만인지 몰라.","JPN":"こうして惜しみなく材料を使うのも久しぶりだ。","ENG":"I don't know how long it's been since I used whatever material I wanted to.","TWN":"已經很久沒有可以這麼盡情地添加材料了。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"감사합니다. 라우라 공.","JPN":"ありがとうございます。ラウラ殿。","ENG":"Thank you, Dame Laura.","TWN":"謝謝你，蘿拉。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"분명히 이 의상으로 콘테스트에 나가면 1등은 따 놓은 당상일 텐데.","JPN":"この衣装でコンテストに出れば1位間違いなしなのにな。","ENG":"This costume would for sure win first prize in a contest.","TWN":"把這件衣服拿去參加比賽的話，一定會得第一名的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"한번 입어볼래? 실제 사이즈가 맞는지 확인을 해봐야 하거든.","JPN":"一度着てみてくれ。サイズが合うかどうか確認したい。","ENG":"Try it on. I have to check if the size fits.","TWN":"要不要試穿一下？看看尺寸合適嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"알겠습니다. 잠시만 기다려주십시오.","JPN":"了解しました。少々お待ちください。","ENG":"Understood. Just a moment.","TWN":"好的，請稍等。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};